/**
 * @fileoverview AjaxForm component definition for JIT pipeline.
 *
 * Bundles design tokens, state machine config, template slot definitions,
 * and Custom Element metadata.
 *
 * @module module/AjaxForm.def
 */

import razyui from '../index.js';
import { PART } from './AjaxForm/constants.js';

/**
 * The definition object for the AjaxForm component.
 * Contains metadata, design tokens, state machine configuration, template slots, and custom element details.
 * 
 * @type {Object}
 */
export const AjaxFormDef = {
    /** @type {string} The name of the component. */
    name: 'AjaxForm',
    
    /** @type {string} The custom element tag name. */
    tag: 'rui-ajax-form',

    // ═══════════════════════════════════════
    //  Design Tokens
    // ═══════════════════════════════════════
    /**
     * Design tokens for styling the AjaxForm component.
     * Defines CSS variables and their default values or references.
     */
    tokens: {
        prefix: 'af',
        tokens: {
            'field-gap':           { value: '1rem',            description: 'Gap between fields' },
            'font-size':           { value: '0.85rem',         description: 'Base font size' },
            'label-font-weight':   { value: '500',             description: 'Label font weight' },
            'label-line-height':   { value: '1.4',             description: 'Label line height' },
            'label-gap':           { value: '0.25rem',         description: 'Gap between label and input' },
            'input-padding':       { value: '0.5rem 0.75rem',  description: 'Input padding' },
            'input-radius':        { ref: 'radius.sm',         description: 'Input border radius' },
            'input-line-height':   { value: '1.25',            description: 'Input line height' },
            'textarea-min-height': { value: '80px',            description: 'Textarea minimum height' },
            'accent':              { ref: 'color.accent',      description: 'Accent color' },
            'accent-hover':        { ref: 'color.accent-hover', description: 'Accent hover color' },
            'bg':                  { ref: 'color.bg',          description: 'Background' },
            'bg-inset':            { ref: 'color.bg-inset',    description: 'Inset background' },
            'border':              { ref: 'color.border',      description: 'Border color' },
            'control-px':          { value: '0.75rem',         description: 'Control horizontal padding' },
            'control-py':          { value: '0.5rem',          description: 'Control vertical padding' },
            'danger':              { ref: 'color.danger',      description: 'Danger / error color' },
            'danger-bg':           { ref: 'color.danger-bg',   description: 'Danger background' },
            'danger-subtle':       { ref: 'color.danger-subtle', description: 'Danger subtle background' },
            'danger-text':         { ref: 'color.danger-text', description: 'Danger text color' },
            'on-accent':           { ref: 'color.on-accent',   description: 'Text on accent' },
            'space-sm':            { value: '0.5rem',          description: 'Small spacing' },
            'text':                { ref: 'color.text',        description: 'Text color' },
            'text-muted':          { ref: 'color.text-muted',  description: 'Muted text color' },
        },
    },

    // ═══════════════════════════════════════
    //  State Machine
    // ═══════════════════════════════════════
    /**
     * State machine configuration for managing the form's submission state.
     */
    states: {
        initial: 'idle',
        states: {
            idle: {
                on: { SUBMIT: 'submitting' },
            },
            submitting: {
                on: { SUCCESS: 'idle', ERROR: 'idle' },
            },
        },
        effects: {
            /**
             * Effect triggered when entering the 'submitting' state.
             * Adds the 'is-submitting' class to the form element.
             * 
             * @param {Object} ctx - The state machine context.
             */
            submitting(ctx) {
                if (ctx.form) razyui(ctx.form).addClass('is-submitting');
            },
            /**
             * Effect triggered when entering the 'idle' state.
             * Removes the 'is-submitting' class from the form element.
             * 
             * @param {Object} ctx - The state machine context.
             */
            idle(ctx) {
                if (ctx.form) razyui(ctx.form).removeClass('is-submitting');
            },
        },
    },

    // ═══════════════════════════════════════
    //  Template Slots
    // ═══════════════════════════════════════
    /**
     * Template slots defining the structure and classes of the form elements.
     */
    template: {
        slots: {
            form:    { element: 'form',  classes: ['af-form'] },
            field:   { element: 'div',   classes: ['af-field', 'form-label'] },
            label:   { element: 'label' },
            input:   { element: 'input' },
            error:   { element: 'div',   classes: ['form-error'] },
            actions: { element: 'div',   classes: ['form-row'] },
        },
    },

    // ═══════════════════════════════════════
    //  JIT Part Styles
    // ═══════════════════════════════════════
    jitParts: {
        [PART.FORM]: PART.FORM,
    },

    styles: {},  /* All styles expressed via JIT */

    // ═══════════════════════════════════════
    //  Custom Element
    // ═══════════════════════════════════════
    observedAttrs: ['action', 'method', 'enctype'],
    attrMap: {
        action:  'action',
        method:  'method',
        enctype: 'enctype',
    },
};

export default AjaxFormDef;
